#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // 1. Create a buffer_adaptor for the provided buffer
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Check available space using buffer_adaptor's free() method
    const auto required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // 3. If insufficient space, return false
    if (adaptor.free() < required_space) {
        return false;
    }

    // 4. Get the write pointer from buffer_adaptor
    auto* write_ptr = adaptor.write_ptr();

    // 5. Write header and items using the write pointer
    // Write header
    std::memcpy(write_ptr, &header, sizeof(header));
    write_ptr += sizeof(header);

    // Write items using binary_stream's write_container method
    hexi::binary_stream stream(adaptor);
    stream.put(items);

    // 6. Return true if write was successful
    return true;
}
```

