void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current position by seeking to absolute position 0 (this gets the current position)
    std::size_t current_pos = 0;
    buffer.write_seek(hexi::buffer_seek::sk_absolute, current_pos);

    // Write header value at position 0
    buffer.write(&header_value, sizeof(header_value));

    // Write some dummy data for the body (e.g., 10 bytes)
    std::vector<std::byte> dummy_data(10, std::byte{0});
    buffer.write(dummy_data.data(), dummy_data.size());

    // Use write_seek with sk_backward and offset equal to body size to go back to header position
    buffer.write_seek(hexi::buffer_seek::sk_backward, dummy_data.size());

    // Update header value at position 0
    buffer.write(&header_value, sizeof(header_value));
}
