};

std::vector<uint8_t> write_typed_data(const TypedData& data) {
    // Create a vector to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_write_adaptor object using the vector
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor_write(buffer);

    // Use the write() method to serialize each field of TypedData
    adaptor_write.write(data.id);
    adaptor_write.write(data.value);
    adaptor_write.write(data.ratio);

